   997→int dbSwapDatabases(int id1, int id2) {
   998→    if (id1 < 0 || id1 >= server.dbnum ||
   999→        id2 < 0 || id2 >= server.dbnum) return C_ERR;
  1000→    if (id1 == id2) return C_OK;
  1001→    redisDb aux = server.db[id1];
  1002→    redisDb *db1 = &server.db[id1], *db2 = &server.db[id2];
  1003→
  1004→    /* Swap hash tables. Note that we don't swap blocking_keys,
  1005→     * ready_keys and watched_keys, since we want clients to
  1006→     * remain in the same DB they were. */
  1007→    db1->dict = db2->dict;
  1008→    db1->expires = db2->expires;
  1009→    db1->avg_ttl = db2->avg_ttl;
  1010→
  1011→    db2->dict = aux.dict;
  1012→    db2->expires = aux.expires;
